export function renderInlineMarkdown(text: string): string {
  let result = text;

  result = result.replace(/```([^`]+)```/g, '\x1b[2m$1\x1b[0m');
  result = result.replace(/`([^`]+)`/g, '\x1b[2m$1\x1b[0m');
  result = result.replace(/\*\*\*(.+?)\*\*\*/g, '\x1b[1;3m$1\x1b[0m');
  result = result.replace(/\*\*(.+?)\*\*/g, '\x1b[1m$1\x1b[0m');
  result = result.replace(/(?<!\*)\*(?!\*)(.+?)(?<!\*)\*(?!\*)/g, '\x1b[3m$1\x1b[0m');
  result = result.replace(/\[(.+?)\]\((.+?)\)/g, '\x1b[34m$1\x1b[0m ($2)');
  result = result.replace(/!\[(.+?)\]\((.+?)\)/g, '[Image: $1] ($2)');
  result = result.replace(/~~(.+?)~~/g, '\x1b[9m$1\x1b[0m');

  return result;
}

export function markdownToPlainText(markdown: string): string {
  return markdown
    .replace(/```[\s\S]*?```/g, '')
    .replace(/`([^`]+)`/g, '$1')
    .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1')
    .replace(/!\[([^\]]*)\]\([^)]+\)/g, '$1')
    .replace(/[#*_~>`\[\]\(\)\!\|]/g, '')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

export function extractCodeBlocks(markdown: string): Array<{ language: string; code: string }> {
  const blocks: Array<{ language: string; code: string }> = [];
  const regex = /```(\w+)?\n([\s\S]*?)```/g;
  let match: RegExpExecArray | null;

  while ((match = regex.exec(markdown)) !== null) {
    blocks.push({
      language: match[1] ?? '',
      code: match[2].trim(),
    });
  }

  return blocks;
}

export function extractHeadings(markdown: string): Array<{ level: number; text: string }> {
  const headings: Array<{ level: number; text: string }> = [];
  const lines = markdown.split('\n');

  for (const line of lines) {
    const match = line.match(/^(#{1,6})\s+(.+)$/);
    if (match) {
      headings.push({
        level: match[1].length,
        text: match[2].trim(),
      });
    }
  }

  return headings;
}

export function wordWrap(text: string, maxWidth = 80): string {
  const lines: string[] = [];
  const words = text.split(/\s+/);

  let currentLine = '';
  for (const word of words) {
    if (currentLine.length + word.length + 1 > maxWidth) {
      if (currentLine) lines.push(currentLine);
      currentLine = word;
    } else {
      currentLine = currentLine ? `${currentLine} ${word}` : word;
    }
  }

  if (currentLine) lines.push(currentLine);
  return lines.join('\n');
}
